// V47.2 Fix: Rate limit throttle for concurrent orders + hasItems guard
const batchItems = $("Batch SKU Collector").all();

// Rate limit guard: only delay when there are real SKUs to fetch
// Prevents Airtable 429 when multiple orders arrive within seconds
const hasValidItems = batchItems.some(item => item.json.hasItems === true);
if (hasValidItems) {
  await new Promise(r => setTimeout(r, 250));
}

// Cache disabled (V47.1 reason: stale zero-cost data on NAS cache)
return batchItems.map(item => ({
  json: { ...item.json, useCache: false }
}));
